import json

def generate_entry(title, desc, components, wiring, explanation):
    """Format a circuit entry as Python dict string."""
    return json.dumps({
        "title": title,
        "type": "circuit_generation",
        "description": desc,
        "components": components,
        "wiring_steps": wiring,
        "explanation": explanation,
        "circuit_diagram_description": title.lower() + " wiring diagram with all components connected as described.",
        "sources": [
            {"name": "Wikipedia - Electronics", "url": "https://en.wikipedia.org/wiki/Electronics"},
            {"name": "Electronics Tutorials", "url": "https://www.electronics-tutorials.ws"},
        ],
    }, indent=4) + ","


if __name__ == "__main__":
    entries = []
    for title, desc, components, wiring, explanation in CIRCUITS:
        entries.append(generate_entry(title, desc, components, wiring, explanation))

    output = "\n".join(entries)
    print(f"Generated {len(CIRCUITS)} circuit entries")
    print(f"\n--- PASTE BELOW INTO sources.py before the closing ']' ---\n")
    print(output)
